import json, re

src='/Users/jins/.claude/projects/-Users-jins-IO-harness/e2806b33-0ab0-45e7-8b11-04a86e59208e.jsonl'
status_block=None
convo=[]      # (role, text)
actions=[]    # compact tool-use log

def text_of(content):
    if isinstance(content,str): return content
    out=[]
    for b in content or []:
        if isinstance(b,dict) and b.get('type')=='text': out.append(b.get('text',''))
    return '\n'.join(out)

with open(src) as f:
    for line in f:
        try: o=json.loads(line)
        except: continue
        t=o.get('type')
        if t=='user':
            m=o.get('message',{}); c=m.get('content')
            txt=text_of(c)
            # capture the SessionStart-injected sofar status block
            if status_block is None and 'Sofar status' in str(o):
                mm=re.search(r'# Sofar status.*?(?=$)', json.dumps(o), re.S)
            if txt.strip():
                if 'hook success' in txt or txt.startswith('<'):
                    pass
                else:
                    convo.append(('USER', txt.strip()))
            # tool results skipped
        elif t=='assistant':
            m=o.get('message',{})
            for b in m.get('content',[]) or []:
                if isinstance(b,dict):
                    if b.get('type')=='text' and b.get('text','').strip():
                        convo.append(('ASSISTANT', b['text'].strip()))
                    elif b.get('type')=='tool_use':
                        n=b.get('name',''); i=b.get('input',{}) or {}
                        brief=''
                        if n in ('Edit','Write','Read'): brief=i.get('file_path','')
                        elif n=='Bash': brief=(i.get('command','') or '')[:120]
                        elif n.startswith('mcp__sofar'): brief=json.dumps({k:v for k,v in i.items() if k in ('task_id','status','chose','summary','next_action')})[:200]
                        elif n=='Agent' or n=='Task': brief=(i.get('description','') or '')[:80]
                        actions.append(f'{n}: {brief}')
        elif t=='system':
            s=json.dumps(o)
            if status_block is None and '# Sofar status' in s:
                c=o.get('content','')
                if isinstance(c,str) and '# Sofar status' in c: status_block=c

# fallback: search raw file for the status block
if status_block is None:
    raw=open(src).read()
    m=re.search(r'# Sofar status: harness-build.*?\(generated by sofar[^"\\]*', raw, re.S)
    if m: status_block=m.group(0).replace('\\n','\n')

open('ceremony-status-block.txt','w').write(status_block or '(NOT FOUND)')
with open('ceremony-convo.txt','w') as f:
    for role,txt in convo:
        f.write(f'\n[{role}]\n{txt}\n')
with open('ceremony-actions.txt','w') as f:
    f.write('\n'.join(actions))
print('status block:', 'FOUND' if status_block else 'MISSING', len(status_block or ''))
print('convo turns:', len(convo), '| chars:', sum(len(t) for _,t in convo))
print('actions:', len(actions))
EOF

